mapper.select:
SELECT t.task_id, t.project_id, t.parent_task_id, t.task_type_code, p.project_name, p.project_type_code, t.task_title, t.task_status, t.priority, t.assignee_user_id, assignee.user_nm AS assignee_user_nm, t.start_date, t.due_date, t.actual_start_date, t.actual_end_date, t.task_url, t.support_amount, t.actual_amount, t.progress_rate, t.wbs_color, t.description, parent.task_title AS parent_task_title, m.milestone_name FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id LEFT JOIN schedule_task parent ON parent.task_id = t.parent_task_id LEFT JOIN schedule_milestone m ON m.milestone_id = t.milestone_id LEFT JOIN schedule_project_member assignee ON assignee.project_id = t.project_id AND assignee.user_id = t.assignee_user_id
AND ( p.owner_user_id = #{viewer_user_id} OR EXISTS ( SELECT 1 FROM schedule_project_member pm WHERE pm.project_id = t.project_id AND pm.user_id = #{viewer_user_id} ) )
AND t.project_id = #{project_id}
AND t.assignee_user_id = #{assignee_user_id}
AND t.task_status = #{task_status}
AND ( t.task_title ILIKE CONCAT('%', #{keyword}, '%') OR p.project_name ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY t.due_date NULLS LAST, t.task_id DESC

SELECT t.task_id, t.project_id, t.parent_task_id, t.task_type_code, p.project_name, p.project_type_code, t.task_title, t.task_status, t.priority, t.assignee_user_id, assignee.user_nm AS assignee_user_nm, t.start_date, t.due_date, t.actual_start_date, t.actual_end_date, t.task_url, t.support_amount, t.actual_amount, t.progress_rate, t.wbs_color, t.description, t.milestone_id, parent.task_title AS parent_task_title, m.milestone_name, t.created_at, t.updated_at FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id LEFT JOIN schedule_task parent ON parent.task_id = t.parent_task_id LEFT JOIN schedule_milestone m ON m.milestone_id = t.milestone_id LEFT JOIN schedule_project_member assignee ON assignee.project_id = t.project_id AND assignee.user_id = t.assignee_user_id
AND t.task_id = #{task_id}
AND ( p.owner_user_id = #{viewer_user_id} OR EXISTS ( SELECT 1 FROM schedule_project_member pm WHERE pm.project_id = t.project_id AND pm.user_id = #{viewer_user_id} ) )

SELECT COUNT(1)
FROM schedule_project p
WHERE p.project_id = #{project_id}

  AND (
      p.owner_user_id = #{viewer_user_id}
      OR EXISTS (
          SELECT 1
          FROM schedule_project_member pm
          WHERE pm.project_id = p.project_id
            AND pm.user_id = #{viewer_user_id}
      )
  )

SELECT COUNT(1)
FROM schedule_project p
WHERE p.project_id = #{project_id}
  AND (
      p.owner_user_id = #{user_id}
      OR EXISTS (
          SELECT 1
          FROM schedule_project_member pm
          WHERE pm.project_id = p.project_id
            AND pm.user_id = #{user_id}
      )
  )

SELECT COUNT(1)
FROM schedule_task_comment
WHERE parent_comment_id = #{parent_comment_id}

    AND comment_id != #{comment_id}

